from dataclasses import dataclass
from typing import Optional
import asyncio
from anthropic import AsyncAnthropic

@dataclass
class WorkerResult:
    success: bool
    content: str
    error: Optional[str] = None

async def safe_worker(task: str, client: AsyncAnthropic) -> WorkerResult:
    """Worker that catches its own errors and returns a typed result."""
    try:
        response = await client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system="Complete this retrieval task.",
            messages=[{"role": "user", "content": task}],
        )
        return WorkerResult(success=True, content=response.content[0].text)
    except Exception as exc:
        return WorkerResult(success=False, content="", error=str(exc))

async def tactical_manager(
    subtasks: list[str],
    client: AsyncAnthropic,
    max_retries: int = 1,
) -> list[str]:
    """Manager that retries failed workers once before escalating."""
    results = []
    for task in subtasks:
        for attempt in range(max_retries + 1):
            result = await safe_worker(task, client)
            if result.success:
                results.append(result.content)
                break
            if attempt == max_retries:
                # Escalate to top orchestrator with context
                raise RuntimeError(
                    f"Worker failed after {max_retries + 1} attempts on task: {task!r}. "
                    f"Last error: {result.error}"
                )
            await asyncio.sleep(2 ** attempt)
    return results
